#include <bits/stdc++.h>
using namespace std;

const int N=50010,mod=1e9+7;

int T,n,a,b,f[N][210],fac[N],inv[N];

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

void init(){
    n=5e4,a=200;
    fac[0]=1;
    for(int i=1;i<=n;i++)
        fac[i]=1ll*fac[i-1]*i%mod;
    inv[n]=qpow(fac[n],mod-2);
    for(int i=n-1;i>=0;i--)
        inv[i]=1ll*inv[i+1]*(i+1)%mod;
    f[0][0]=1;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=a;j++)
            f[i][j]=(f[i-1][j-1]+1ll*f[i-1][j]*(i-1))%mod;
}

int C(int n,int m){
    if(m<0 || n<m) return 0;
    return 1ll*fac[n]*inv[n-m]%mod*inv[m]%mod;
}

int main(){
    init();
    scanf("%d",&T);
    while(T--){
        scanf("%d%d%d",&n,&a,&b);
        printf("%d\n",1ll*f[n-1][a+b-2]*C(a+b-2,a-1)%mod);
    }
    return 0;
}
